import React from 'react';

function CustomParallax({ scrollPercentage, layers, offset }) {
  return (
    <div className="CustomParallaxWrapper">
      <div className="CustomParallax">
        {layers.map((layer, index) => (
          <div
            key={index}
            className={`Layer${index + 1}`}
            style={{
              backgroundImage: `url('${layer.image}')`,
              backgroundPositionX: `calc(${scrollPercentage * layer.speed}% + ${offset})`
            }}
          ></div>
        ))}
      </div>
    </div>
  );
}

export default CustomParallax;
